INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('immigration-1aab856d-moex-00350', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '有關不作為犯之類型與成立要件，下列敘述何者正確？', '["不作為犯可分為主觀不作為犯與客觀不作為犯兩種", "不作為犯之成立，以行為人對於犯罪結果之發生，具有保證人地位為前提", "所謂保證人地位，係指對於犯罪結果之發生，法律上有防止之義務，故單純的契約義務並不構 成保證人地位", "行為人因自己行為致有發生犯罪結果之危險者，因尚未必一定導致結果發生，故仍不負防止其 發生之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00351', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '有關刑法上之禁止錯誤，下列敘述何者正確？', '["所謂禁止錯誤，係指行為人主觀上對於客觀的犯罪構成要件事實產生誤認而言", "所謂禁止錯誤，係指行為人對於具體事實之認識並無錯誤，但對於該具體事實在法律上評價亦 即行為違法性之認識有誤而言", "依新近實務見解，行為人對於補充空白刑法的法律或行政命令內容有所誤認，均不屬禁止錯誤， 而屬構成要件錯誤", "行為人有禁止錯誤之情形，除無正當理由而可避免者外，不得因不知法律而免除刑事責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00352', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '下列刑法瀆職罪章之犯罪，何者非公務員之行為人亦得單獨犯之？', '["洩漏國防以外秘密罪", "違背職務收受賄賂罪", "枉法裁判罪", "凌虐人犯罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00353', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '下列情形中，何者之行為構成刑法第135條第3項規定之加重妨害公務罪？', '["甲遭警方盤查時，為避免員警查獲其身上準備販售予他人之違法槍械，動手推擠員警，企圖逃逸", "乙家中遭法院查封，遂夥同家人等三人，於法院執行處人員欲在家門口貼上查封文件時，以蠻 力攔阻", "丙接到朋友電話求助，遂駕駛車輛高速駛至朋友遭警方臨檢現場，下車對員警叫囂，且毆打員警", "丁騎乘機車途中遭遇酒駕臨檢，為避免被警方發現自己是通緝犯，在警方攔停時以機車衝撞員 警，致員警倒地後逃逸"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00354', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲駕駛汽車行駛於高速公路上，在開啟自動輔助駕駛系統即閉目養神，未注意車前狀況。不料該 車自動輔助駕駛系統判讀錯誤，未偵測到前方路面停放一台工程防撞車，仍持續直行並高速撞擊 工程防撞車，致該防撞車毀損，現場人員幸無傷害。甲一時驚慌，匆忙改回手動駕駛，加速逃離 現場不久後，再度撞上其他車輛，導致車內駕駛受到輕傷，甲才遭警方攔住無法離去。甲之行為 構成下列何種犯罪？', '["第354條之毀損罪", "第185條之損壞或壅塞陸路致生往來之危險罪", "第185條之4之發生交通事故逃逸罪", "第284條之過失傷害罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00355', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '下列情形中，何者構成刑法第339條之詐欺罪？', '["甲持偽造之10元硬幣，在自動販賣機購買飲料", "乙持撿來的他人提款卡在提款機提款", "丙持偽造之他人存摺印章向銀行櫃臺人員提款", "丁持他人之帳號密碼，登入他人網路銀行，將他人帳戶中之存款匯款至自己之銀行帳戶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00356', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '關於同一案件繫屬於有管轄權的數法院時，由何法院審判，下列敘述何者正確？', '["由繫屬在先之法院審判", "由法院間協調決定", "由當事人合意決定", "由有最重要牽連關係之法院審判"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00357', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '具原住民身分的甲涉犯賭博罪。偵查後，檢察官向法院聲請簡易判決處刑，下列敘述何者正確？', '["甲不得選任辯護人，因為賭博罪是輕罪", "甲不得選任辯護人，因檢察官是向法院聲請簡易判決處刑", "甲未選任辯護人者，審判長應指定公設辯護人或律師為其辯護", "甲未選任辯護人者，審判長無須指定公設辯護人或律師為其辯護"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00358', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲涉嫌犯有竊盜罪。偵查中，檢察官向法院聲請羈押。下列敘述何者正確？', '["甲未選任辯護人者，審判長應指定公設辯護人或律師為其辯護", "甲未選任辯護人者，審判長無須指定公設辯護人或律師為其辯護，因竊盜為輕罪", "甲的辯護人在羈押程序中，得檢閱卷宗及證物，但不得抄錄或攝影，以維偵查不公開原則", "甲的辯護人在羈押程序中，不得檢閱卷宗及證物，以維偵查不公開原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00359', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '偵查中，檢察官認犯罪嫌疑人甲涉嫌詐欺罪，犯罪嫌疑重大，且無一定住、居所。下列關於限制 出境、出海的敘述，何者正確？', '["經法院裁定後，得限制甲出境或出海", "檢察官得逕行限制甲出境或出海", "限制出境、出海的書面，應立即通知甲，使其得以即時聲明不服", "限制出境、出海前，應予甲陳述意見的機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "4a00528f970c", "answer_pdf_sha1": "3667ce999189", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
